   "exitcode" : 0,
   "exited" : 1,
   "out-data" : "update ir_ui_view set arch_db=E'{\"de_DE\": \"<t name=\\\\\"Contact Us\\\\\" t-name=\\\\\"website.contactus\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        .frawo-contact-hero{background:linear-gradient(135deg,#064e3b 0%,#14532d 55%,#052e16 100%);color:#f0fdf4;position:relative;overflow:hidden;}\\\\n        .frawo-contact-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -8% -35% auto;width:28rem;height:28rem;border-radius:50%;background:radial-gradient(circle,#a855f755 0%,#a855f700 72%);}\\\\n        .frawo-contact-card{border:none;border-radius:1.4rem;background:#ffffff;box-shadow:0 24px 60px rgba(6,78,59,.10);height:100%;}\\\\n        .frawo-contact-card h3{color:#064e3b;font-weight:800;}\\\\n        .frawo-contact-kicker{letter-spacing:.22em;text-transform:uppercase;color:#a7f3d0;font-weight:700;font-size:.82rem;}\\\\n        .frawo-contact-btn{background:#064e3b;border-color:#064e3b;}\\\\n      </style>\\\\n      <section class=\\\\\"frawo-contact-hero pt96 pb96\\\\\">\\\\n        <div class=\\\\\"container position-relative\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-8\\\\\">\\\\n              <div class=\\\\\"frawo-contact-kicker mb-3\\\\\">FraWo Kontakt</div>\\\\n              <h1 class=\\\\\"display-4 mb-3\\\\\">Direkter Draht statt Kontaktformular-Zirkus.</h1>\\\\n              <p class=\\\\\"lead mb-0\\\\\">Wenn es um Website, digitale Betriebsablaeufe oder Medienpfade geht, ist Mail aktuell der schnellste Einstieg. Fuer kurze Rueckfragen geht auch der direkte Telefonpfad.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 text-lg-end\\\\\">\\\\n              <a class=\\\\\"btn btn-light btn-lg me-2 mb-2\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a>\\\\n              <a class=\\\\\"btn btn-outline-light btn-lg mb-2\\\\\" href=\\\\\"/radio/public/frawo-funk\\\\\">FraWo Funk</a>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"pt64 pb96\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4\\\\\">\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">E-Mail</h3>\\\\n                <p class=\\\\\"mb-3\\\\\">Projektanfragen, Rueckfragen und Abstimmungen laufen aktuell am saubersten per Mail.</p>\\\\n                <p class=\\\\\"mb-0\\\\\"><a href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a></p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4\\\\\">\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Telefon</h3>\\\\n                <p class=\\\\\"mb-3\\\\\">Wenn etwas schnell geklaert werden soll, ist der direkte Operator-Pfad offen.</p>\\\\n                <p class=\\\\\"mb-0\\\\\"><a href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a></p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4\\\\\">\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Standort</h3>\\\\n                <p class=\\\\\"mb-3\\\\\">FraWo sitzt in Weissensberg und baut von dort Medien-, Website- und Betriebsprozesse mit Bodenhaftung.</p>\\\\n                <p class=\\\\\"mb-0\\\\\">Rothkreuz 14<br/>88138 Weissensberg</p>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n          <div class=\\\\\"row g-5 align-items-center pt64\\\\\">\\\\n            <div class=\\\\\"col-lg-7\\\\\">\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:#064e3b;font-weight:900;\\\\\">Womit koennen wir helfen?</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">FraWo verbindet Marke, Betrieb und Medienpraesenz. Entsprechend hilfreich ist eine kurze Mail mit Kontext: Was soll live gehen, was soll stabiler werden, und welche Rolle spielt die Website oder der Medienpfad dabei?</p>\\\\n              <p class=\\\\\"mb-0\\\\\">Wenn du direkt loslegen willst, nimm den Mailpfad. Fuer einen ersten Eindruck der Medienlinie gibt es den Radio-Einstieg direkt auf der Website.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-5\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4 p-lg-5\\\\\">\\\\n                <h3 class=\\\\\"h3 mb-3\\\\\">Naechster Schritt</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">Schreib kurz, worum es geht. Wir ordnen den Fall sauber ein und melden uns auf dem passenden Weg zurueck.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary frawo-contact-btn\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=FraWo%20Projektanfrage\\\\\">Projekt anfragen</a>\\\\n                  <a class=\\\\\"btn btn-outline-secondary\\\\\" href=\\\\\"/\\\\\">Zur Startseite</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\", \"en_US\": \"<t name=\\\\\"Contact Us\\\\\" t-name=\\\\\"website.contactus\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        .frawo-contact-hero{background:linear-gradient(135deg,#064e3b 0%,#14532d 55%,#052e16 100%);color:#f0fdf4;position:relative;overflow:hidden;}\\\\n        .frawo-contact-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -8% -35% auto;width:28rem;height:28rem;border-radius:50%;background:radial-gradient(circle,#a855f755 0%,#a855f700 72%);}\\\\n        .frawo-contact-card{border:none;border-radius:1.4rem;background:#ffffff;box-shadow:0 24px 60px rgba(6,78,59,.10);height:100%;}\\\\n        .frawo-contact-card h3{color:#064e3b;font-weight:800;}\\\\n        .frawo-contact-kicker{letter-spacing:.22em;text-transform:uppercase;color:#a7f3d0;font-weight:700;font-size:.82rem;}\\\\n        .frawo-contact-btn{background:#064e3b;border-color:#064e3b;}\\\\n      </style>\\\\n      <section class=\\\\\"frawo-contact-hero pt96 pb96\\\\\">\\\\n        <div class=\\\\\"container position-relative\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-8\\\\\">\\\\n              <div class=\\\\\"frawo-contact-kicker mb-3\\\\\">FraWo Contact</div>\\\\n              <h1 class=\\\\\"display-4 mb-3\\\\\">A direct line, not a maze of forms.</h1>\\\\n              <p class=\\\\\"lead mb-0\\\\\">For website, digital operations or media-path work, email is currently the fastest way in. Short questions can also go through the direct phone path.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 text-lg-end\\\\\">\\\\n              <a class=\\\\\"btn btn-light btn-lg me-2 mb-2\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a>\\\\n              <a class=\\\\\"btn btn-outline-light btn-lg mb-2\\\\\" href=\\\\\"/radio/public/frawo-funk\\\\\">FraWo Funk</a>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"pt64 pb96\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4\\\\\">\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Email</h3>\\\\n                <p class=\\\\\"mb-3\\\\\">Project requests, follow-ups and coordination currently work best via email.</p>\\\\n                <p class=\\\\\"mb-0\\\\\"><a href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a></p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4\\\\\">\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Phone</h3>\\\\n                <p class=\\\\\"mb-3\\\\\">If something needs a quick answer, the direct operator path is available.</p>\\\\n                <p class=\\\\\"mb-0\\\\\"><a href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a></p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4\\\\\">\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Location</h3>\\\\n                <p class=\\\\\"mb-3\\\\\">FraWo operates from Weissensberg and builds media, website and business-process paths with real-world grounding.</p>\\\\n                <p class=\\\\\"mb-0\\\\\">Rothkreuz 14<br/>88138 Weissensberg</p>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n          <div class=\\\\\"row g-5 align-items-center pt64\\\\\">\\\\n            <div class=\\\\\"col-lg-7\\\\\">\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:#064e3b;font-weight:900;\\\\\">What do you need help with?</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">FraWo connects brand, operations and media presence. A short email with context helps most: what needs to go live, what should become more reliable, and how the website or media path fits into it.</p>\\\\n              <p class=\\\\\"mb-0\\\\\">If you want to get started right away, use the email path. For a first impression of the media line, the radio entry is already live on the website.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-5\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4 p-lg-5\\\\\">\\\\n                <h3 class=\\\\\"h3 mb-3\\\\\">Next step</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">Send a short note about the request. We will sort it cleanly and come back through the right path.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary frawo-contact-btn\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=FraWo%20Project%20Request\\\\\">Start a project</a>\\\\n                  <a class=\\\\\"btn btn-outline-secondary\\\\\" href=\\\\\"/\\\\\">Back to homepage</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\"}' where id=3637;\nupdate ir_ui_view set arch_db=E'{\"de_DE\": \"\\\\n<t name=\\\\\"Home\\\\\" t-name=\\\\\"website.homepage\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <t t-set=\\\\\"pageName\\\\\" t-value=\\\\\"''homepage''\\\\\"/>\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        .frawo-hero{background:linear-gradient(135deg,#f0fdf4 0%,#ffffff 55%,#ecfdf5 100%);position:relative;overflow:hidden;}\\\\n        .frawo-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -10% -35% auto;width:32rem;height:32rem;border-radius:50%;background:radial-gradient(circle,#a855f733 0%,#a855f700 70%);pointer-events:none;}\\\\n        .frawo-eyebrow{letter-spacing:.32em;text-transform:uppercase;color:#a855f7;font-weight:700;font-size:.85rem;}\\\\n        .frawo-title{color:#064e3b;font-weight:900;line-height:.95;}\\\\n        .frawo-sub{color:#14532d;font-size:1.15rem;max-width:42rem;}\\\\n        .frawo-chip{display:inline-flex;align-items:center;gap:.55rem;padding:.55rem .9rem;border-radius:999px;background:#ffffffcc;border:1px solid #d1fae5;color:#064e3b;font-weight:700;backdrop-filter:blur(10px);}\\\\n        .frawo-card{height:100%;border:none;border-radius:1.4rem;background:#ffffff;box-shadow:0 24px 60px rgba(6,78,59,.10);}\\\\n        .frawo-card h3{color:#064e3b;font-weight:800;}\\\\n        .frawo-number{font-size:2.2rem;font-weight:900;color:#a855f7;line-height:1;}\\\\n        .frawo-band{background:#064e3b;color:#f0fdf4;border-radius:1.5rem;}\\\\n        .frawo-band a{color:#ffffff;}\\\\n        .frawo-kicker{color:#a7f3d0;font-weight:700;letter-spacing:.18em;text-transform:uppercase;font-size:.8rem;}\\\\n        .frawo-outline{border:2px solid #064e3b;color:#064e3b;background:transparent;}\\\\n        .frawo-outline:hover{background:#064e3b;color:#fff;}\\\\n      </style>\\\\n\\\\n      <section class=\\\\\"frawo-hero pt96 pb96\\\\\">\\\\n        <div class=\\\\\"container position-relative\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-7\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">FraWo GbR</div>\\\\n              <h1 class=\\\\\"display-2 frawo-title mb-4\\\\\">Smart Media &amp; Event</h1>\\\\n              <p class=\\\\\"frawo-sub mb-4\\\\\">Altes Handwerkswissen trifft moderne Technik-Liebhaberei: digitale Betriebsprozesse, klare Umsetzungen und ein eigener Radio- und Medienpfad fuer Projekte mit Handschlagqualitaet.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3 mb-4\\\\\">\\\\n                <a class=\\\\\"btn btn-primary btn-lg\\\\\" style=\\\\\"background:#064e3b;border-color:#064e3b;\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">Projekt anfragen</a>\\\\n                <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"/radio/public/frawo-funk\\\\\">FraWo Funk hoeren</a>\\\\n              </div>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-2\\\\\">\\\\n                <span class=\\\\\"frawo-chip\\\\\">Digitale Betriebsablaeufe</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Web &amp; Automation</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Radio &amp; Medienpraesenz</span>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-5 text-lg-end text-center\\\\\">\\\\n              <img src=\\\\\"/web/image/website/1/logo\\\\\" alt=\\\\\"FraWo Logo\\\\\" class=\\\\\"img-fluid\\\\\" style=\\\\\"max-width:460px;width:100%;filter:drop-shadow(0 24px 40px rgba(6,78,59,.12));\\\\\"/>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"pt64 pb32\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">01</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Digitale Ordnung</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Kontrollierte Arbeitsablaeufe mit Odoo, Nextcloud und Paperless statt Zettelchaos, Medienbruch und blindem Tool-Wildwuchs.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">02</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Website mit Rueckgrat</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Keine austauschbare Visitenkarte, sondern ein klarer Auftritt mit Kontaktpfad, Markenlinie und technischer Substanz im Hintergrund.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">03</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Media &amp; Event</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo Funk und die Medienpraesenz bleiben nicht Nebenschauplatz, sondern Teil einer eigenstaendigen, wiedererkennbaren Handschrift.</p>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"pt32 pb32\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"frawo-band p-5 p-lg-6\\\\\">\\\\n            <div class=\\\\\"row align-items-center g-4\\\\\">\\\\n              <div class=\\\\\"col-lg-7\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\">Arbeitsweise</div>\\\\n                <h2 class=\\\\\"display-6 mb-3\\\\\">Anpacker mit Koepfchen, sauber bis in den Betriebspfad.</h2>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo verbindet bodenstaendige Umsetzung mit technischer Praezision: Infrastruktur, Website, Dokumente und Kommunikation greifen kontrolliert ineinander statt sich gegenseitig zu blockieren.</p>\\\\n              </div>\\\\n              <div class=\\\\\"col-lg-5\\\\\">\\\\n                <ul class=\\\\\"list-unstyled mb-0 d-grid gap-3\\\\\">\\\\n                  <li><strong>Analyse:</strong> Erst den echten Zustand lesen, dann bauen.</li>\\\\n                  <li><strong>Aufbau:</strong> Klare Systeme, klare Rollen, klare Rueckwege.</li>\\\\n                  <li><strong>Livegang:</strong> Nutzbar fuer Alltag, Team und sichtbare Praesentation.</li>\\\\n                </ul>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"pt32 pb96\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">Wofuer FraWo steht</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:#064e3b;font-weight:900;\\\\\">Klartext statt Blendwerk.</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">Wir moegen Loesungen, die im Alltag tragen: nachvollziehbar, robust und ohne kuenstlich aufgeblasene Komplexitaet.</p>\\\\n              <p class=\\\\\"mb-0\\\\\">Genau deshalb ist auch diese Seite bewusst fokussiert: Marke, Kontakt und ein direkter Einstieg in den FraWo-Medienpfad.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4 p-lg-5\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:#a855f7;\\\\\">Kontakt</div>\\\\n                <h3 class=\\\\\"h2 mb-3\\\\\">Projekt, Idee oder Rueckfrage?</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">Am schnellsten erreichst du FraWo aktuell per Mail. Fuer Medien und die laufende Funk-Praesenz gibt es zusaetzlich den direkten Radio-Pfad.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary\\\\\" style=\\\\\"background:#064e3b;border-color:#064e3b;\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a>\\\\n                  <a class=\\\\\"btn frawo-outline\\\\\" href=\\\\\"/radio/public/frawo-funk\\\\\">Zum Radio</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\\\\n\", \"en_US\": \"\\\\n<t name=\\\\\"Home\\\\\" t-name=\\\\\"website.homepage\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <t t-set=\\\\\"pageName\\\\\" t-value=\\\\\"''homepage''\\\\\"/>\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        .frawo-hero{background:linear-gradient(135deg,#f0fdf4 0%,#ffffff 55%,#ecfdf5 100%);position:relative;overflow:hidden;}\\\\n        .frawo-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -10% -35% auto;width:32rem;height:32rem;border-radius:50%;background:radial-gradient(circle,#a855f733 0%,#a855f700 70%);pointer-events:none;}\\\\n        .frawo-eyebrow{letter-spacing:.32em;text-transform:uppercase;color:#a855f7;font-weight:700;font-size:.85rem;}\\\\n        .frawo-title{color:#064e3b;font-weight:900;line-height:.95;}\\\\n        .frawo-sub{color:#14532d;font-size:1.15rem;max-width:42rem;}\\\\n        .frawo-chip{display:inline-flex;align-items:center;gap:.55rem;padding:.55rem .9rem;border-radius:999px;background:#ffffffcc;border:1px solid #d1fae5;color:#064e3b;font-weight:700;backdrop-filter:blur(10px);}\\\\n        .frawo-card{height:100%;border:none;border-radius:1.4rem;background:#ffffff;box-shadow:0 24px 60px rgba(6,78,59,.10);}\\\\n        .frawo-card h3{color:#064e3b;font-weight:800;}\\\\n        .frawo-number{font-size:2.2rem;font-weight:900;color:#a855f7;line-height:1;}\\\\n        .frawo-band{background:#064e3b;color:#f0fdf4;border-radius:1.5rem;}\\\\n        .frawo-band a{color:#ffffff;}\\\\n        .frawo-kicker{color:#a7f3d0;font-weight:700;letter-spacing:.18em;text-transform:uppercase;font-size:.8rem;}\\\\n        .frawo-outline{border:2px solid #064e3b;color:#064e3b;background:transparent;}\\\\n        .frawo-outline:hover{background:#064e3b;color:#fff;}\\\\n      </style>\\\\n\\\\n      <section class=\\\\\"frawo-hero pt96 pb96\\\\\">\\\\n        <div class=\\\\\"container position-relative\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-7\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">FraWo GbR</div>\\\\n              <h1 class=\\\\\"display-2 frawo-title mb-4\\\\\">Smart Media &amp; Event</h1>\\\\n              <p class=\\\\\"frawo-sub mb-4\\\\\">Altes Handwerkswissen trifft moderne Technik-Liebhaberei: digitale Betriebsprozesse, klare Umsetzungen und ein eigener Radio- und Medienpfad fuer Projekte mit Handschlagqualitaet.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3 mb-4\\\\\">\\\\n                <a class=\\\\\"btn btn-primary btn-lg\\\\\" style=\\\\\"background:#064e3b;border-color:#064e3b;\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">Start a project</a>\\\\n                <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"/radio/public/frawo-funk\\\\\">Listen to FraWo Funk</a>\\\\n              </div>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-2\\\\\">\\\\n                <span class=\\\\\"frawo-chip\\\\\">Digital operations</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Web &amp; automation</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Radio &amp; media presence</span>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-5 text-lg-end text-center\\\\\">\\\\n              <img src=\\\\\"/web/image/website/1/logo\\\\\" alt=\\\\\"FraWo Logo\\\\\" class=\\\\\"img-fluid\\\\\" style=\\\\\"max-width:460px;width:100%;filter:drop-shadow(0 24px 40px rgba(6,78,59,.12));\\\\\"/>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"pt64 pb32\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">01</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Digital order</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Controlled business flows with Odoo, Nextcloud and Paperless instead of scattered notes, media breaks and random tool chaos.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">02</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Website with backbone</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Not a generic business card website, but a clear presence with contact path, brand line and technical substance behind it.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">03</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Media &amp; event</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo Funk and the media presence are not an afterthought, but part of a recognisable and independent signature.</p>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"pt32 pb32\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"frawo-band p-5 p-lg-6\\\\\">\\\\n            <div class=\\\\\"row align-items-center g-4\\\\\">\\\\n              <div class=\\\\\"col-lg-7\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\">How we work</div>\\\\n                <h2 class=\\\\\"display-6 mb-3\\\\\">Hands-on people with technical discipline.</h2>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo combines grounded execution with technical precision: infrastructure, website, documents and communication are built to work together instead of getting in each other''s way.</p>\\\\n              </div>\\\\n              <div class=\\\\\"col-lg-5\\\\\">\\\\n                <ul class=\\\\\"list-unstyled mb-0 d-grid gap-3\\\\\">\\\\n                  <li><strong>Read first:</strong> understand the real situation before changing it.</li>\\\\n                  <li><strong>Build clean:</strong> clear systems, clear roles, clear rollback paths.</li>\\\\n                  <li><strong>Go live:</strong> usable for everyday work, teams and presentation.</li>\\\\n                </ul>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"pt32 pb96\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">What FraWo stands for</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:#064e3b;font-weight:900;\\\\\">Straight talk instead of empty gloss.</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">We prefer solutions that survive real work: understandable, robust and without artificially inflated complexity.</p>\\\\n              <p class=\\\\\"mb-0\\\\\">That is why this page stays focused on brand, contact and a direct entry point into the FraWo media path.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4 p-lg-5\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:#a855f7;\\\\\">Contact</div>\\\\n                <h3 class=\\\\\"h2 mb-3\\\\\">Project, idea or question?</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">The fastest way to reach FraWo is currently by mail. For the media side and the live audio presence, the radio path is available directly.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary\\\\\" style=\\\\\"background:#064e3b;border-color:#064e3b;\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a>\\\\n                  <a class=\\\\\"btn frawo-outline\\\\\" href=\\\\\"/radio/public/frawo-funk\\\\\">Open radio</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\\\\n\"}' where id=3636;\nupdate ir_ui_view set arch_db=E'{\"de_DE\": \"\\\\n<t name=\\\\\"Home\\\\\" t-name=\\\\\"website.homepage\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <t t-set=\\\\\"pageName\\\\\" t-value=\\\\\"''homepage''\\\\\"/>\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        .frawo-hero{background:linear-gradient(135deg,#f0fdf4 0%,#ffffff 55%,#ecfdf5 100%);position:relative;overflow:hidden;}\\\\n        .frawo-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -10% -35% auto;width:32rem;height:32rem;border-radius:50%;background:radial-gradient(circle,#a855f733 0%,#a855f700 70%);pointer-events:none;}\\\\n        .frawo-eyebrow{letter-spacing:.32em;text-transform:uppercase;color:#a855f7;font-weight:700;font-size:.85rem;}\\\\n        .frawo-title{color:#064e3b;font-weight:900;line-height:.95;}\\\\n        .frawo-sub{color:#14532d;font-size:1.15rem;max-width:42rem;}\\\\n        .frawo-chip{display:inline-flex;align-items:center;gap:.55rem;padding:.55rem .9rem;border-radius:999px;background:#ffffffcc;border:1px solid #d1fae5;color:#064e3b;font-weight:700;backdrop-filter:blur(10px);}\\\\n        .frawo-card{height:100%;border:none;border-radius:1.4rem;background:#ffffff;box-shadow:0 24px 60px rgba(6,78,59,.10);}\\\\n        .frawo-card h3{color:#064e3b;font-weight:800;}\\\\n        .frawo-number{font-size:2.2rem;font-weight:900;color:#a855f7;line-height:1;}\\\\n        .frawo-band{background:#064e3b;color:#f0fdf4;border-radius:1.5rem;}\\\\n        .frawo-band a{color:#ffffff;}\\\\n        .frawo-kicker{color:#a7f3d0;font-weight:700;letter-spacing:.18em;text-transform:uppercase;font-size:.8rem;}\\\\n        .frawo-outline{border:2px solid #064e3b;color:#064e3b;background:transparent;}\\\\n        .frawo-outline:hover{background:#064e3b;color:#fff;}\\\\n      </style>\\\\n\\\\n      <section class=\\\\\"frawo-hero pt96 pb96\\\\\">\\\\n        <div class=\\\\\"container position-relative\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-7\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">FraWo GbR</div>\\\\n              <h1 class=\\\\\"display-2 frawo-title mb-4\\\\\">Smart Media &amp; Event</h1>\\\\n              <p class=\\\\\"frawo-sub mb-4\\\\\">Altes Handwerkswissen trifft moderne Technik-Liebhaberei: digitale Betriebsprozesse, klare Umsetzungen und ein eigener Radio- und Medienpfad fuer Projekte mit Handschlagqualitaet.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3 mb-4\\\\\">\\\\n                <a class=\\\\\"btn btn-primary btn-lg\\\\\" style=\\\\\"background:#064e3b;border-color:#064e3b;\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">Projekt anfragen</a>\\\\n                <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"/radio/public/frawo-funk\\\\\">FraWo Funk hoeren</a>\\\\n              </div>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-2\\\\\">\\\\n                <span class=\\\\\"frawo-chip\\\\\">Digitale Betriebsablaeufe</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Web &amp; Automation</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Radio &amp; Medienpraesenz</span>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-5 text-lg-end text-center\\\\\">\\\\n              <img src=\\\\\"/web/image/website/1/logo\\\\\" alt=\\\\\"FraWo Logo\\\\\" class=\\\\\"img-fluid\\\\\" style=\\\\\"max-width:460px;width:100%;filter:drop-shadow(0 24px 40px rgba(6,78,59,.12));\\\\\"/>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"pt64 pb32\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">01</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Digitale Ordnung</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Kontrollierte Arbeitsablaeufe mit Odoo, Nextcloud und Paperless statt Zettelchaos, Medienbruch und blindem Tool-Wildwuchs.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">02</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Website mit Rueckgrat</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Keine austauschbare Visitenkarte, sondern ein klarer Auftritt mit Kontaktpfad, Markenlinie und technischer Substanz im Hintergrund.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">03</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Media &amp; Event</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo Funk und die Medienpraesenz bleiben nicht Nebenschauplatz, sondern Teil einer eigenstaendigen, wiedererkennbaren Handschrift.</p>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"pt32 pb32\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"frawo-band p-5 p-lg-6\\\\\">\\\\n            <div class=\\\\\"row align-items-center g-4\\\\\">\\\\n              <div class=\\\\\"col-lg-7\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\">Arbeitsweise</div>\\\\n                <h2 class=\\\\\"display-6 mb-3\\\\\">Anpacker mit Koepfchen, sauber bis in den Betriebspfad.</h2>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo verbindet bodenstaendige Umsetzung mit technischer Praezision: Infrastruktur, Website, Dokumente und Kommunikation greifen kontrolliert ineinander statt sich gegenseitig zu blockieren.</p>\\\\n              </div>\\\\n              <div class=\\\\\"col-lg-5\\\\\">\\\\n                <ul class=\\\\\"list-unstyled mb-0 d-grid gap-3\\\\\">\\\\n                  <li><strong>Analyse:</strong> Erst den echten Zustand lesen, dann bauen.</li>\\\\n                  <li><strong>Aufbau:</strong> Klare Systeme, klare Rollen, klare Rueckwege.</li>\\\\n                  <li><strong>Livegang:</strong> Nutzbar fuer Alltag, Team und sichtbare Praesentation.</li>\\\\n                </ul>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"pt32 pb96\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">Wofuer FraWo steht</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:#064e3b;font-weight:900;\\\\\">Klartext statt Blendwerk.</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">Wir moegen Loesungen, die im Alltag tragen: nachvollziehbar, robust und ohne kuenstlich aufgeblasene Komplexitaet.</p>\\\\n              <p class=\\\\\"mb-0\\\\\">Genau deshalb ist auch diese Seite bewusst fokussiert: Marke, Kontakt und ein direkter Einstieg in den FraWo-Medienpfad.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4 p-lg-5\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:#a855f7;\\\\\">Kontakt</div>\\\\n                <h3 class=\\\\\"h2 mb-3\\\\\">Projekt, Idee oder Rueckfrage?</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">Am schnellsten erreichst du FraWo aktuell per Mail. Fuer Medien und die laufende Funk-Praesenz gibt es zusaetzlich den direkten Radio-Pfad.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary\\\\\" style=\\\\\"background:#064e3b;border-color:#064e3b;\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a>\\\\n                  <a class=\\\\\"btn frawo-outline\\\\\" href=\\\\\"/radio/public/frawo-funk\\\\\">Zum Radio</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  